var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_QM","text":{"KOREA":"저…… 고맙습니다.","JPN":"あの……ありがとうございます。","ENG":"Uh... Thank you.","TWN":"那個…謝謝你。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_NULL","text":{"KOREA":"이름.","JPN":"名は。","ENG":"Name?","TWN":"名字。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"아, 저는 아샤라고 해요.","JPN":"あ、私は、アーシャと申します。","ENG":"Oh, I'm Asha.","TWN":"喔，我叫阿莎。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_NULL","text":{"KOREA":"아샤…….","JPN":"アーシャ……","ENG":"Asha...","TWN":"阿莎……"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_NULL","text":{"KOREA":"윽……!","JPN":"うっ……！","ENG":"Ugh...!","TWN":"呃……！好沉。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"괘, 괜찮으세요? 역시 아까 다치신 건……!","JPN":"だ、大丈夫ですか？　やっぱりさっきので怪我を……！","ENG":"A-are you all right? Were you injured just before…!?","TWN":"你，你沒事吧？哪裡受傷了嗎……！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L19_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_NULL","text":{"KOREA":"조금…… 어지럽군. 너무 오랜만에 움직인 모양이야.","JPN":"少し……めまいが。久しぶりに動いたせいだろう。","ENG":"I'm... just a little dizzy. It's been so long since I moved.","TWN":"嗯……我有點頭暈。可能是太久沒動的關係。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_NULL","text":{"KOREA":"부축해 줘서 고맙다.","JPN":"支えてくれて助かる。","ENG":"Thanks for supporting me.","TWN":"謝謝你扶我。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"그 악명 높은 스캐빈저를 쓰러뜨리시다니……!","JPN":"あの悪名高きスカベンジャーを倒してしまうなんて……！","ENG":"I can't believe you defeated those infamous Scavengers...!","TWN":"你竟然可以打敗惡名昭彰的清道夫……！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"역시…… 강한 카운터로군요.","JPN":"やっぱり……強いカウンターだったんですね。","ENG":"You... really are a strong Counter.","TWN":"不愧是……厲害的制裁者。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"저…… 혹시 부탁이 있는데…….","JPN":"あの……実はお願いしたいことが……","ENG":"Um... I have a favor to ask...","TWN":"那個……我可以拜託你一件事嗎……"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_NULL","text":{"KOREA":"거절하지.","JPN":"断る。","ENG":"I refuse.","TWN":"不可以。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"아니, 듣지도 않고 거절부터 하는 게 어딨어요!","JPN":"まだ何も言ってないのに、酷いです！","ENG":"What? How can you refuse when you didn't even hear what it was?","TWN":"拜託，哪有人聽都沒聽就先拒絕的啦！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"DAUGHTER_EXTRA_NULL_GIRL","text":{"KOREA":"저기요. 언니. 엄마, 아빠 좀 찾아주면 안 돼요?","JPN":"あのぉ、お姉ちゃん。お母さんとお父さんを探してくれませんか？","ENG":"Um, hello. Could you help me find my mom and dad?","TWN":"不好意思，你可以幫我找爸爸媽媽，還有姊姊嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DAUGHTER_EXTRA_NULL_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"DAUGHTER_EXTRA_NULL_GIRL","text":{"KOREA":"여기 잠깐만 있으면 된다 그랬는데…….","JPN":"ここにちょっとだけいればいいって言ったのに……","ENG":"They said I just needed to stay here for a moment...","TWN":"他們叫我在這裡待一下，可是……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DAUGHTER_EXTRA_NULL_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_NULL","text":{"KOREA":"……. ","JPN":"…… ","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"제가 아버지를 찾을 수 있게 도와주시면 안 될까요?","JPN":"私のお父さんを探す、手助けをしてくれませんか？","ENG":"Could you help me find my father?","TWN":"你可以幫我找到爸爸嗎？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"왜 무시하시는 건데요!! 이유라도 알려줘요!","JPN":"どうして話を聞いてくれないんですか！？　理由を教えてください！","ENG":"Why are you ignoring me?! At least give me a reason!","TWN":"為什麼不回應我！！起碼告訴我個理由吧！"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"제가 저 동면 캡슐인지 뭔지에서 꺼내드렸잖아요!","JPN":"冬眠カプセルみたいなものから出してあげたじゃないですか！","ENG":"I got you out of that hibernation capsule thingy!","TWN":"是我把你從那個冬眠膠囊還什麼鬼東西裡弄出來的！"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_NULL","text":{"KOREA":"그리고 나는 네 목숨을 구했지.","JPN":"私は君の命を救った。","ENG":"And I saved your life.","TWN":"但你的命是我救的。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_NULL","text":{"KOREA":"친절하게 이유까지 설명해 준 것만 해도 벌써 10번째다.","JPN":"丁寧に理由も説明したはずだ、10回もな。","ENG":"This is the tenth time I've kindly explained that to you.","TWN":"而且我已經好聲好氣地跟你解釋過十遍了。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"역시 돈 때문인가요? 돈이 없어 보이니까 외면하시는 거죠?","JPN":"やっぱりお金ですか？　お金がなさそうだから、相手にしてくれないんですか！？","ENG":"Is it because of money? Are you declining to help because I look poor?","TWN":"果然是錢的問題對不對？因為我看起來沒錢，你才不想理我對不對？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L16_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_NULL","text":{"KOREA":"쓸데없는 소리 말고 가족한테 돌아가.","JPN":"いいから家族のところに戻れ。","ENG":"Stop talking nonsense and go back to your family.","TWN":"少胡說八道，快回去找你家人吧。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L18_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"어머니는 진작에 침식 재난으로 돌아가시고, 아버지는 기억에도 없어요.","JPN":"お母さんは侵食災害で亡くなって、お父さんは物心がついた頃にはもういなかったんです。","ENG":"My mother died in a Corruption Disaster a long time ago, and I have no memory of my father.","TWN":"我媽媽早就因為侵蝕災難過世了，爸爸根本沒有出現在我的記憶裡。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"저한테 남은 건, 이 빌어먹을 나침반뿐이라고요.","JPN":"私に残っているのは、このわけのわからない羅針盤だけなんです。","ENG":"All that I have left is this stupid compass.","TWN":"我僅有的，就只有這個該死的指南針。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"그간 혼자서 떠돌아다니다가, 이제야 겨우 단서를 찾은 것 같단 말이에요.","JPN":"ずっと一人で放浪していて、やっと手がかりを見つけたと思ったのに……","ENG":"I've been wandering alone for all this time, and I think that I've finally found a clue.","TWN":"這段時間我一個人到處找，現在好不容易終於找到一點線索。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":null,"text":{"KOREA":"■샤■■ 안부■ ■해■.","JPN":"■■シャ■よろし■伝■■■■。","ENG":"■ay ■■llo to ■sha fo■ ■e.","TWN":"■我■■莎■ ■好■。"},"stage":{"bg":"MAINSTREAM_6100016","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_NULL","text":{"KOREA":"큭……!","JPN":"くっ……！","ENG":"Khhk...!","TWN":"咳……！"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"역시 다친 게 맞는 거죠?","JPN":"やっぱり、怪我をしてるんですよね？","ENG":"How bad are your injuries?","TWN":"你果然受傷了對吧？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_NULL","text":{"KOREA":"……오랜만에 걸어서 균형을 잃은 것뿐이야. 난 멀쩡하다.","JPN":"……久しぶりに歩いたからバランスを崩しただけだ。心配ない。","ENG":"...I just lost my balance, that's all. I'm fine.","TWN":"……我只是因為太久沒走路，一時失去平衡而已。我沒事。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_NULL","text":{"KOREA":"우선 여기까지 오게 된 경위를 설명해라.","JPN":"それより、ここに来ることになった経緯を聞かせてくれ。","ENG":"First, explain how you got here.","TWN":"你先說說你為何會到這裡來吧。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"제가 어릴 때부터 가지고 다녔던 나침반이에요.","JPN":"これは私が幼い頃から持っていた羅針盤です。","ENG":"This is the compass that I've had since I was little.","TWN":"這是我從小就帶在身上的指南針。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L43_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"이유는 모르겠지만 북쪽을 가리키지 않고, <color=#ffd34c>특정한 무언가</color>에 반응한다는 걸 알았어요.","JPN":"どういうわけか、この羅針盤の針は北を指さず、<color=#ffd34c>特定の何か</color>に反応しています。","ENG":"I don't know why, but I learned that it doesn't point north and reacts to <color=#ffd34c>something</color>.","TWN":"原因我也不太清楚，但它不會指向北方，而是對<color=#ffd34c>特定的東西</color>會產生反應。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"처음엔 고장 난 줄 알았는데, 일정한 방향성이 있다는 것을 알게 되었죠.","JPN":"初めは壊れたんじゃないかって思っていましたが、次第に同じ方向を指し続けていることに気が付きました。","ENG":"I thought it was broken at first, but I found out that it's pointing to a certain direction.","TWN":"我一開始還以為是壞掉的關係，後來才發現它有一定的方向性。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"하염없이 이 바늘이 가리키는 방향으로 돌아다니다 보니 이곳까지 오게 되었어요.","JPN":"その針が指す方向に進み続けていたら、ここに辿りつくようになって……","ENG":"So, I ended up here as I followed wherever the compass pointed to.","TWN":"然後我就漫無目的地照著它指的方向走，就走到這裡來囉。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"그리고 바늘이 가리키는 목적지는 당신이었고요.","JPN":"そして、針が指す先に、あなたがいました。","ENG":"And it was pointing to you.","TWN":"而針所指的目的地就是你。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_NULL","text":{"KOREA":"동결의 부작용인진 몰라도, 기억에 손실이 생겼어.","JPN":"凍結されていたせいか、記憶が損傷している。","ENG":"Maybe it's a side effect of being in hibernation, but I have some memory loss.","TWN":"不知道是不是冰凍的副作用，我失去了記憶。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_NULL","text":{"KOREA":"누가 거칠게 뜯은 것처럼, 기억이 파편화되어 있다.","JPN":"まるで引き裂かれたかのように、記憶が断片的になっている。","ENG":"My memories are fragmented, as if someone had torn them apart.","TWN":"像是有人用力將記憶撕碎一般，記憶全都變成碎片。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_NULL","text":{"KOREA":"내 이름은 물론, 어쩌다 이곳에 얼어 있었는지조차 기억나지 않아.","JPN":"自分の名前も、どうしてここで凍らされていたのかも思い出せない。","ENG":"I can't recall why I was frozen in a place like this, or even my name.","TWN":"不管是我的名字，或是我為什麼會冰在這裡，我一點都想不起來。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_NULL","text":{"KOREA":"나는 분명…… 어떤 약속을…….","JPN":"確か私は……何か約束を……","ENG":"I think... there was some kind of promise...","TWN":"這樣的我……怎麼能承諾什……"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"기억이…….","JPN":"記憶が……","ENG":"You lost your memories...","TWN":"你的記憶……"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"이제 와서 말하긴 좀 그렇지만…… 억지를 부려서 죄송해요.","JPN":"今更ですが……無理を言ってごめんなさい。","ENG":"It may be a bit late to say this, but... I'm sorry for insisting that you help.","TWN":"現在才說這些有點不好意思……但很抱歉，剛才是我太無理取鬧。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L9_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"강한 카운터들을 고용하려면 비싼 값이 들거든요. 그래서…… 저도 모르게…….","JPN":"強いカウンターを雇うには、費用がかかるので、それで……つい……","ENG":"It's expensive to hire a strong Counter like yourself. So... without thinking–","TWN":"因為雇用厲害的制裁者要花很多錢，所以…我才不自覺地……"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_NULL","text":{"KOREA":"카운터를 고용한다고? 무슨 헛소리지?","JPN":"カウンターを雇う？　いったい何を言っているのだ？","ENG":"Hire Counters? What are you talking about?","TWN":"雇用制裁者？你在說什麼？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_NULL","text":{"KOREA":"카운터 각성은 희귀한 현상이야. 관리국의 정보망이 아니라면 쉽사리 파악하기 힘들다.","JPN":"カウンター覚醒は極めて稀な事例だ。管理局の情報網でなければ、彼らの所在を把握することは困難のはずだが。","ENG":"A Counter's awakening is a rare phenomenon. Without the Administration's information network, it will be difficult to find one.","TWN":"制裁者覺醒是很稀有的現象，若非管理局的情報網，普通人是無法輕易掌握的。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"소재 파악이…… 힘들다고요?","JPN":"所在把握が……困難……？","ENG":"Difficult... to find one?","TWN":"無法輕易……掌握？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"카운터는 관리국을 통해 신원을 등록하게 되어 있어요.","JPN":"カウンターは管理局に情報を登録するよう義務付けられています。","ENG":"All Counters are registered through the Administration.","TWN":"管理局都有登記制裁者的身分資料。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"그쪽이야말로 무슨 말씀을 하시는지 모르겠네요.","JPN":"あなたこそ、おかしなことを言っていますよ。","ENG":"I should ask you what you're talking about.","TWN":"我聽不懂你在說什麼。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L18_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"그럼, 태스크포스도 모르시는 거예요?","JPN":"まさか、タスクフォースも知らないんですか？","ENG":"Then, you don't know about TASKFORCEs?","TWN":"那你知道特遣勢力嗎？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_NULL","text":{"KOREA":"태스크포스?","JPN":"タスクフォース？","ENG":"TASKFORCEs?","TWN":"特遣勢力？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"20년 전, 대정화 전쟁을 겪은 뒤 출범한 민간 군사 조직이죠.","JPN":"20年前、大浄化戦争を経て、民間によって立ち上げられた軍事組織です。","ENG":"They are private military organizations that emerged twenty years ago after the Grand Purification War.","TWN":"就是20年前的淨化之戰後開始成立的民間軍事組織。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"대부분의 카운터는 태스크포스에 소속되어 활동한다고요.","JPN":"大半のカウンターは、タスクフォース所属として活動しているんですよ。","ENG":"The majority of Counters work under a TASKFORCE.","TWN":"大部分的制裁者都隸屬在特遣勢力之下。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"도대체 언제부터 저기 얼어 계셨던 거예요?","JPN":"いったいいつから、あそこで凍らされていたんですか？","ENG":"How long have you been frozen in there?","TWN":"你到底是什麼時候開始躺在那裡的？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_NULL","text":{"KOREA":"……20년 전의 이야기라고?","JPN":"……20年前だと？","ENG":"...You say that was twenty years ago?","TWN":"……你說20年前？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"}]`);export{e as default};